+const createGatsbyDoc = (
+  filePath,
+  query,
+  { isHook, isStaticQuery } = { isHook: false, isStaticQuery: false }
+) => {
+  const doc = parse(query)
+  return {
+    filePath,
+    doc,
+    text: query,
+    isHook,
+    isStaticQuery,
+    hash: `hash`,
+    templateLoc: {
+      start: {
+        // so no idea, but it seems to work correctly on websites
+        line: 1,
+        column: 0,
+      },
+      end: {
+        line: 1,
+        column: 0,
+      },
+    },
+  }
+}

