index 5e64ef4..ed8cec0 100644
--- a/packages/gatsby/src/query/__tests__/query-compiler.js
+++ b/packages/gatsby/src/query/__tests__/query-compiler.js
@@ -775,6 +775,333 @@ describe(`actual compiling`, () => {
   })
 })

+describe(`Extra fields`, () => {
+  let schema
+  beforeAll(async () => {
+    const sdl = await fs.readFile(
+      path.join(__dirname, `./fixtures/query-compiler-schema.graphql`),
+      { encoding: `utf-8` }
+    )
+    schema = buildSchema(sdl)
+  })
+
+  const transformQuery = queryString => {
+    const nodes = [createGatsbyDoc(`mockFile`, queryString)]
+    const errors = []
+    const result = processQueries({
+      schema,
+      parsedQueries: nodes,
+      addError: e => {
+        errors.push(e)
+      },
+    })
+    return [result, errors]
+  }
+
+  it(`adds __typename field to abstract types`, async () => {
+    const [result, errors] = transformQuery(`
+      query mockFileQuery {
+        allDirectory {
+          nodes {
+            contents {
+              ... on File {
+                id
+              }
+            }
+            children {
+              id
+            }
+          }
+        }
+      }
+    `)
+    expect(errors).toEqual([])
+    expect(result.get(`mockFile`)).toMatchSnapshot()
+  })
+
+  it(`adds __typename field to abstract types within inline fragments`, async () => {
+    const [result, errors] = transformQuery(`
+      query mockFileQuery {
+        allDirectory {
+          nodes {
+            ... on Directory {
+              contents {
+                ... on File {
+                  id
+                }
+              }
+              children {
+                id
+              }
+            }
+          }
+        }
+      }
+    `)
+    expect(errors).toEqual([])
+    expect(result.get(`mockFile`)).toMatchSnapshot()
+  })
+
+  it(`adds __typename field to abstract types within fragments`, async () => {
+    const [result, errors] = transformQuery(`
+      query mockFileQuery {
+        allDirectory {
+          nodes {
+            ...DirectoryContents
+          }
+        }
+      }
+      fragment DirectoryContents on Directory {
+        contents {
+          ... on File {
+            id
+          }
+        }
+        children {
+          id
+        }
+      }
+    `)
+    expect(errors).toEqual([])
+    expect(result.get(`mockFile`)).toMatchSnapshot()
+  })
+
+  it(`adds __typename field to abstract types in the query of arbitrary depth`, async () => {
+    const [result, errors] = transformQuery(`
+      query mockFileQuery {
+        allDirectory {
+          nodes {
+            contents {
+              ... on Directory {
+                contents {
+                  ... on Directory {
+                    contents {
+                      ... on Directory {
+                        id
+                      }
+                    }
+                    children {
+                      id
+                    }
+                  }
+                }
+              }
+            }
+            children {
+              children {
+                children {
+                  id
+                }
+                ... on Directory {
+                  contents {
+                    ... on File {
+                      id
+                    }
+                  }
+                }
+              }
+            }
+          }
+        }
+      }
+    `)
+    expect(errors).toEqual([])
+    expect(result.get(`mockFile`)).toMatchSnapshot()
+  })
+
+  it(`doesn't add __typename field to abstract types twice`, async () => {
+    const [result, errors] = transformQuery(`
+      query mockFileQuery {
+        allDirectory {
+          nodes {
+            contents {
+              __typename
+              ... on File {
+                id
+              }
+              ... FileOrDirectory
+            }
+            children {
+              __typename
+              ... Node
+            }
+            ... on Directory {
+              contents {
+                __typename
+              }
+              children {
+                __typename
+              }
+            }
+            ...DirectoryContents
+          }
+        }
+      }
+
+      fragment DirectoryContents on Directory {
+        contents {
+          __typename
+        }
+        children {
+          __typename
+        }
+      }
+
+      fragment FileOrDirectory on FileOrDirectory {
+        __typename
+      }
+
+      fragment Node on Node {
+        __typename
+      }
+    `)
+    expect(errors).toEqual([])
+    expect(result.get(`mockFile`)).toMatchSnapshot()
+  })
+
+  it(`adds id field if type has it`, () => {
+    const [result, errors] = transformQuery(`
+      query mockFileQuery {
+        allDirectory {
+          nodes {
+            __typename
+          }
+        }
+      }
+    `)
+    expect(errors).toEqual([])
+    expect(result.get(`mockFile`)).toMatchSnapshot()
+  })
+
+  it(`adds id field within inline fragment if type has it`, () => {
+    const [result, errors] = transformQuery(`
+      query mockFileQuery {
+        allDirectory {
+          nodes {
+            ... on Directory {
+              __typename
+            }
+          }
+        }
+      }
+    `)
+    expect(errors).toEqual([])
+    expect(result.get(`mockFile`)).toMatchSnapshot()
+  })
+
+  it(`adds id field within fragment if type has it`, () => {
+    const [result, errors] = transformQuery(`
+      query mockFileQuery {
+        allDirectory {
+          nodes {
+            ... Directory
+          }
+        }
+      }
+      fragment Directory on Directory {
+        __typename
+      }
+
+    `)
+    expect(errors).toEqual([])
+    expect(result.get(`mockFile`)).toMatchSnapshot()
+  })
+
+  it(`adds id field in the query of arbitrary depth`, () => {
+    const [result, errors] = transformQuery(`
+      query mockFileQuery {
+        allDirectory {
+          nodes {
+            contents {
+              ... on Directory {
+                contents {
+                  ... on Directory {
+                    contents {
+                      ... on File {
+                        __typename
