+                      ... on Directory {
+                        __typename
+                      }
+                    }
+                  }
+                }
+              }
+            }
+            children {
+              children {
+                children {
+                  __typename
+                }
+                ... on Directory {
+                  contents {
+                    ... on File {
+                      __typename
+                    }
+                  }
+                }
+              }
+            }
+          }
+        }
+      }
+    `)
+    expect(errors).toEqual([])
+    expect(result.get(`mockFile`)).toMatchSnapshot()
+  })
+
+  it(`doesn't add id field twice`, async () => {
+    const [result, errors] = transformQuery(`
+      query mockFileQuery {
+        allDirectory {
+          nodes {
+            id
